import unittest
from src.retry_policy import delay_seconds, should_retry

class RetryPolicyTests(unittest.TestCase):
    def test_retryable_statuses(self):
        self.assertEqual([s for s in (400, 401, 429, 500, 503) if should_retry(s)], [429, 500, 503])

    def test_backoff(self):
        self.assertEqual([delay_seconds(i) for i in range(1, 6)], [0.25, 0.5, 1.0, 2.0, 2.0])

