import csv
import json
from pathlib import Path

latest = {}
for source in sorted(Path('data').glob('*.csv')):
    with source.open(newline='') as stream:
        for row in csv.DictReader(stream):
            current = latest.get(row['order_id'])
            if current is None or row['updated_at'] > current['updated_at']:
                latest[row['order_id']] = row
paid = sorted((row for row in latest.values() if row['status'] == 'paid'), key=lambda row: row['order_id'])
summary = {'paid_orders': len(paid), 'paid_revenue': sum(int(row['amount']) for row in paid), 'order_ids': [row['order_id'] for row in paid]}
out = Path('out')
out.mkdir(exist_ok=True)
(out / 'summary.json').write_text(json.dumps(summary, indent=2) + '\n')
(out / 'report.md').write_text(f"# Paid order reconciliation\n\nPaid orders: {summary['paid_orders']}\n\nPaid revenue: {summary['paid_revenue']}\n")

