class Cache:
    def __init__(self, clock):
        self.clock = clock
        self.entries = {}

    def set(self, key, value, ttl):
        self.entries[key] = (value, self.clock() + ttl)

    def get(self, key):
        value, expires_at = self.entries[key]
        if expires_at < self.clock():
            del self.entries[key]
            raise KeyError(key)
        return value

